mapper.select:
SELECT DISTINCT subject_id
FROM t_vote_item
WHERE uid = #{uid}
  AND valid_flag = 1
  AND subject_id IN

      #{subjectId}

mapper.insert:
INSERT INTO t_vote_item (
    subject_id, opid, uid, target_id, property_area, choice, signature_hash, vote_channel
) VALUES (
    #{subjectId}, #{opid}, #{uid}, #{targetId}, #{propertyArea}, #{choice}, #{signatureHash}, #{voteChannel}
)

mapper.select:
SELECT vote_id, subject_id, opid, uid, target_id, property_area,
       choice, voted_at, signature_hash, vote_channel,
       valid_flag, invalid_reason, invalidated_at
FROM t_vote_item
WHERE subject_id = #{subjectId}
  AND opid = #{opid}
  AND valid_flag = 1
  AND (
      (#{targetId,jdbcType=BIGINT} IS NULL AND target_id IS NULL)
      OR target_id = #{targetId,jdbcType=BIGINT}
  )
ORDER BY voted_at DESC, vote_id DESC
LIMIT 1

SELECT d.opid, d.uid, d.building_id, d.room_id, d.property_area, d.auth_level, d.vote_id, d.choice, d.voted_at FROM ( SELECT DISTINCT ON (op.opid) op.opid, op.uid, op.building_id, op.room_id, op.build_area AS property_area, cu.auth_level, vi.vote_id, vi.choice, vi.voted_at FROM c_owner_property op JOIN c_user cu ON cu.uid = op.uid LEFT JOIN t_vote_item vi ON vi.subject_id = #{subjectId} AND vi.opid = op.opid AND vi.valid_flag = 1 WHERE op.tenant_id = #{tenantId} AND op.account_status = 1
AND op.building_id = #{scopeReferenceId}
ORDER BY op.opid, vi.voted_at ASC ) d ORDER BY d.building_id, d.room_id, d.opid LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*)
FROM c_owner_property op
WHERE op.tenant_id = #{tenantId}
  AND op.account_status = 1

    AND op.building_id = #{scopeReferenceId}
